{
  "worker_id": 3,
  "phase": "01e",
  "items": [
    {
      "source_file": "outputs/01b_PARTIAL_W2B3_1770279561.json",
      "status": "success",
      "trust_model": {
        "actors": [
          {
            "id": "actor-blob-submitter",
            "name": "Blob Submitter (External Data Provider)",
            "description": "Any entity that submits blob data to the system for encoding into polynomial commitments and cells. The blob is raw bytes of exactly BYTES_PER_BLOB length. This is the outermost data origin and the system's primary untrusted input surface. Blob content determines all downstream polynomial evaluations, KZG proofs, and data columns."
          },
          {
            "id": "actor-kzg-trusted-setup",
            "name": "KZG Trusted Setup (KZG_SETUP_G1_MONOMIAL / KZG_SETUP_G2_MONOMIAL)",
            "description": "The cryptographic trusted setup ceremony that produced the structured reference string (SRS) used in KZG_SETUP_G1_MONOMIAL and KZG_SETUP_G2_MONOMIAL. This is a foundational trust anchor: all KZG proof generation (SG-014 compute_kzg_proof_multi_impl) and batch verification (SG-015 verify_cell_kzg_proof_batch_impl) depend on these parameters being honestly generated. If the toxic waste from the ceremony was not destroyed, the entire commitment scheme is broken."
          },
          {
            "id": "actor-polynomial-engine",
            "name": "Polynomial Arithmetic Engine",
            "description": "The internal computational module implementing polynomial operations over BLS12-381 scalar fields: FFT (SG-003, SG-004), coset FFT (SG-005), polynomial addition (SG-008), multiplication (SG-009), division (SG-010), interpolation (SG-011), vanishing polynomial construction (SG-012), and Horner evaluation (SG-013). This engine is trusted as a correct implementation of finite field arithmetic."
          },
          {
            "id": "actor-cell-encoder",
            "name": "Cell Encoder / Decoder",
            "description": "The component responsible for serializing and deserializing field elements to/from cell byte representations (SG-001 cell_to_coset_evals, SG-002 coset_evals_to_cell). It bridges the byte-level blob representation and the algebraic field element domain. Encoding/decoding correctness is critical: any error here corrupts all downstream polynomial operations."
          },
          {
            "id": "actor-proof-generator",
            "name": "KZG Proof Generator",
            "description": "The component that generates KZG multi-opening proofs for cells (SG-014 compute_kzg_proof_multi_impl, SG-019 compute_cells_and_kzg_proofs_polynomialcoeff, SG-020 compute_cells_and_kzg_proofs). It computes quotient polynomials and commits them using the trusted setup. The proof generator must produce proofs that are verifiable by any honest verifier."
          },
          {
            "id": "actor-batch-verifier",
            "name": "Batch KZG Proof Verifier",
            "description": "The component that performs batched verification of multiple cell KZG proofs in a single pairing check (SG-015 verify_cell_kzg_proof_batch_impl, SG-021 verify_cell_kzg_proof_batch). It uses the Fiat-Shamir heuristic (SG-006) to derive a random challenge for aggregation. This is the primary cryptographic gatekeeper: it determines whether cells and proofs are accepted as valid."
          },
          {
            "id": "actor-recovery-engine",
            "name": "Data Recovery Engine (Reed-Solomon Erasure Coding)",
            "description": "The component that recovers the original polynomial from a subset of cells using Reed-Solomon erasure coding techniques (SG-023 recover_polynomialcoeff, SG-024 recover_cells_and_kzg_proofs). It requires at least 50% of cells (CELLS_PER_EXT_BLOB / 2) to be available. Recovery correctness is essential for data availability guarantees."
          },
          {
            "id": "actor-fiat-shamir-oracle",
            "name": "Fiat-Shamir Random Oracle (Hash Function)",
            "description": "The hash function (hash_to_bls_field) used to derive the random challenge r for batch verification via the Fiat-Shamir heuristic (SG-006 compute_verify_cell_kzg_proof_batch_challenge). This transforms the interactive proof protocol into a non-interactive one. The hash function is assumed to behave as a random oracle."
          },
          {
            "id": "actor-validator-node",
            "name": "Validator Node (Honest Validator)",
            "description": "A consensus-layer validator that computes cells from blobs (SG-002 cells_and_kzg_proofs_construction), constructs data column sidecars (SG-003 get_data_column_sidecars), publishes sidecars to gossip subnets (SG-006 sidecar_publishing), and retains sidecars for the required epochs (SG-007 sidecar_retention). Validators have custody requirements proportional to their stake (SG-001 get_validators_custody_requirement)."
          },
          {
            "id": "actor-beacon-state",
            "name": "Beacon State (Consensus State)",
            "description": "The beacon chain state that provides validator effective balances for custody requirement computation (SG-001), block headers for sidecar construction (SG-004), and KZG commitments for data integrity verification. The state is assumed to be the canonical finalized or justified state."
          },
          {
            "id": "actor-gossip-network",
            "name": "Gossip Network (Data Column Subnets)",
            "description": "The GossipSub network layer over which data column sidecars are published (SG-006 sidecar_publishing). Each sidecar is published to a deterministic subnet based on column_index. The network is an untrusted transport: messages may be dropped, duplicated, reordered, or injected by adversaries."
          },
          {
            "id": "actor-data-requester",
            "name": "Data Requester (Peer / Light Client)",
            "description": "Any entity requesting data column sidecars from a validator during the retention period (SG-007 sidecar_retention). The validator MUST serve sidecars when requested during the retention period. The requester is untrusted and may attempt to exhaust the validator's resources."
          }
        ],
        "trust_boundaries": [
          {
            "id": "tb-001",
            "from_actor": "actor-blob-submitter",
            "to_actor": "actor-cell-encoder",
            "description": "Raw blob bytes cross into the cryptographic domain when cell_to_coset_evals (SG-001) converts byte segments into BLS field elements via bytes_to_bls_field. Malformed or adversarial blob data could encode values outside the valid field range. The assertion len(blob) == BYTES_PER_BLOB (SG-018 INV-001, SG-020 INV-002) is the first validation gate."
          },
          {
            "id": "tb-002",
            "from_actor": "actor-cell-encoder",
            "to_actor": "actor-polynomial-engine",
            "description": "Deserialized field elements from cells are passed to the polynomial engine for FFT, interpolation, and evaluation. The polynomial engine trusts that input field elements are valid members of the BLS12-381 scalar field. If bytes_to_bls_field produces invalid field elements, all polynomial operations produce incorrect results."
          },
          {
            "id": "tb-003",
            "from_actor": "actor-polynomial-engine",
            "to_actor": "actor-proof-generator",
            "description": "Polynomial coefficients produced by polynomial_eval_to_coeff (SG-007) are consumed by compute_kzg_proof_multi_impl (SG-014) to generate KZG proofs. The proof generator trusts the polynomial engine to produce correct coefficient representations. An incorrect inverse FFT or bit-reversal permutation would produce invalid proofs that fail verification."
          },
          {
            "id": "tb-004",
            "from_actor": "actor-kzg-trusted-setup",
            "to_actor": "actor-proof-generator",
            "description": "The proof generator uses KZG_SETUP_G1_MONOMIAL from the trusted setup to compute g1_lincomb (SG-014, q_commit). The entire security of the KZG commitment scheme rests on the trusted setup being honestly generated. This is a static, ceremony-level trust boundary that cannot be verified at runtime."
          },
          {
            "id": "tb-005",
            "from_actor": "actor-kzg-trusted-setup",
            "to_actor": "actor-batch-verifier",
            "description": "The batch verifier uses both KZG_SETUP_G1_MONOMIAL[:n] and KZG_SETUP_G2_MONOMIAL[n] from the trusted setup in the pairing check (SG-015). If the structured reference string is compromised, an adversary can forge proofs that pass batch verification for arbitrary data."
          },
          {
            "id": "tb-006",
            "from_actor": "actor-fiat-shamir-oracle",
            "to_actor": "actor-batch-verifier",
            "description": "The batch verifier derives the random challenge r from the hash function via compute_verify_cell_kzg_proof_batch_challenge (SG-006). The challenge r must be unpredictable before all inputs are committed. The Fiat-Shamir heuristic security requires the hash function to behave as a random oracle and that all verifier-relevant data is included in the hash input (SG-006 INV-001)."
          },
          {
            "id": "tb-007",
            "from_actor": "actor-blob-submitter",
            "to_actor": "actor-batch-verifier",
            "description": "When externally supplied cells, commitments, and proofs are presented for batch verification (SG-021 verify_cell_kzg_proof_batch), all inputs cross from the untrusted external domain into the verifier. The verifier performs exhaustive input validation: length checks (INV-002), commitment byte length (BYTES_PER_COMMITMENT), cell index bounds (INV-004), cell byte length (BYTES_PER_CELL), and proof byte length (BYTES_PER_PROOF)."
          },
          {
            "id": "tb-008",
            "from_actor": "actor-data-requester",
            "to_actor": "actor-recovery-engine",
            "description": "Partial cell sets provided for recovery (SG-024 recover_cells_and_kzg_proofs) cross into the recovery engine. The recovery engine validates: matching lengths (INV-001), at least 50% cell availability (INV-002), no duplicate indices (INV-003), sorted indices (INV-003), valid index bounds (INV-004), and correct cell byte lengths. A malicious requester could provide inconsistent cells that lead to recovery of an incorrect polynomial."
          },
          {
            "id": "tb-009",
            "from_actor": "actor-recovery-engine",
            "to_actor": "actor-proof-generator",
            "description": "The recovered polynomial from recover_polynomialcoeff (SG-023) is passed to compute_cells_and_kzg_proofs_polynomialcoeff (SG-019) to regenerate all cells and proofs. If the recovery engine produces an incorrect polynomial (e.g., due to adversarial cell inputs or insufficient cell count), all regenerated proofs will be invalid."
          },
          {
            "id": "tb-010",
            "from_actor": "actor-validator-node",
            "to_actor": "actor-gossip-network",
            "description": "Validators publish data column sidecars to gossip subnets (SG-006 sidecar_publishing). Each sidecar is deterministically routed to subnet compute_subnet_for_data_column_sidecar(column_index). The validator trusts the network to propagate sidecars, but the network may drop, censor, or delay them. Publishing to the wrong subnet would prevent peers from receiving the data."
          },
          {
            "id": "tb-011",
            "from_actor": "actor-beacon-state",
            "to_actor": "actor-validator-node",
            "description": "The beacon state provides validator effective balances used to compute custody requirements (SG-001 get_validators_custody_requirement). Custody is proportional to stake: total_node_balance // BALANCE_PER_ADDITIONAL_CUSTODY_GROUP, clamped to [VALIDATOR_CUSTODY_REQUIREMENT, NUMBER_OF_CUSTODY_GROUPS]. The validator trusts the state to be canonical. A stale or forked state would produce incorrect custody assignments."
          },
          {
            "id": "tb-012",
            "from_actor": "actor-data-requester",
            "to_actor": "actor-validator-node",
            "description": "During the retention period (MIN_EPOCHS_FOR_DATA_COLUMN_SIDECARS_REQUESTS), validators MUST serve sidecars on request (SG-007). Requesters are untrusted: they may flood the validator with requests (DoS), request data outside the retention window, or attempt to extract custody group membership information."
          },
          {
            "id": "tb-013",
            "from_actor": "actor-validator-node",
            "to_actor": "actor-cell-encoder",
            "description": "During sidecar construction (SG-002 cells_and_kzg_proofs_construction), the validator uses compute_cells to decompose blobs into cells and pairs them with proofs from blobs_bundle.proofs. The validator trusts that blobs_bundle.proofs are correctly aligned with cells: proofs[start:end] for each blob (INV-003). Misaligned proof slicing would produce sidecars with invalid cell-proof pairings."
          },
          {
            "id": "tb-014",
            "from_actor": "actor-validator-node",
            "to_actor": "actor-proof-generator",
            "description": "get_data_column_sidecars_from_block (SG-004) extracts KZG commitments and computes a Merkle inclusion proof from the signed block. The block is trusted (already validated), but the Merkle proof computation is a cryptographic operation that must correctly target the blob_kzg_commitments field in the block body. An incorrect proof would cause sidecar rejection by peers."
          }
        ],
        "assumptions": [
          {
            "id": "asm-001",
            "text": "KZG Trusted Setup Integrity: The structured reference string (KZG_SETUP_G1_MONOMIAL, KZG_SETUP_G2_MONOMIAL) was honestly generated during the trusted setup ceremony and all toxic waste was destroyed. If the discrete log relationships between setup elements are known to an adversary, they can forge valid KZG proofs for arbitrary polynomials, breaking all data availability guarantees."
          },
          {
            "id": "asm-002",
            "text": "BLS12-381 Cryptographic Hardness: The security of all KZG commitments, proofs, and pairing-based verification relies on the computational hardness of the discrete logarithm problem in BLS12-381 G1/G2 groups and the bilinear Diffie-Hellman assumption in the pairing group."
          },
          {
            "id": "asm-003",
            "text": "Random Oracle Model for Fiat-Shamir: The hash function hash_to_bls_field used in compute_verify_cell_kzg_proof_batch_challenge (SG-006) behaves as a random oracle. This is essential for the Fiat-Shamir transformation that converts interactive proof verification into non-interactive batch verification. A weak hash function could allow an adversary to predict the challenge r and craft inputs that pass verification despite invalid proofs."
          },
          {
            "id": "asm-004",
            "text": "Domain Separator Uniqueness: RANDOM_CHALLENGE_KZG_CELL_BATCH_DOMAIN (SG-006 INV-002) is globally unique across all protocols using the same hash function. This prevents cross-protocol replay attacks where a valid Fiat-Shamir challenge from one protocol context is reused in another."
          },
          {
            "id": "asm-005",
            "text": "Field Element Serialization Correctness: bytes_to_bls_field and bls_field_to_bytes (used in SG-001, SG-002) are assumed to be correct inverse operations for valid field elements. If serialization is lossy or non-injective, round-trip encoding errors corrupt cell data."
          },
          {
            "id": "asm-006",
            "text": "Polynomial Arithmetic Correctness: FFT (SG-003, SG-004), coset FFT (SG-005), polynomial addition (SG-008), multiplication (SG-009), division (SG-010), interpolation (SG-011), and evaluation (SG-013) are all assumed to be correctly implemented over the BLS12-381 scalar field. Any bug in these operations would silently produce incorrect proofs or failed verifications."
          },
          {
            "id": "asm-007",
            "text": "Roots of Unity Correctness: compute_roots_of_unity produces primitive roots of unity of the correct order for the BLS12-381 scalar field. PRIMITIVE_ROOT_OF_UNITY (SG-005 INV-001) must be a genuine primitive root. Incorrect roots would make FFT and coset evaluations algebraically meaningless."
          },
          {
            "id": "asm-008",
            "text": "Bit-Reversal Permutation Consistency: bit_reversal_permutation is applied consistently in polynomial_eval_to_coeff (SG-007), coset_shift_for_cell (SG-016), coset_for_cell (SG-017), and recover_polynomialcoeff (SG-023). Any inconsistency in permutation application between encoding and decoding paths would produce misaligned evaluations."
          },
          {
            "id": "asm-009",
            "text": "Reed-Solomon Recovery Threshold: Data recovery (SG-023, SG-024) requires at least 50% of cells (CELLS_PER_EXT_BLOB / 2). This is the information-theoretic minimum for a rate-1/2 Reed-Solomon code over the extension domain. Below this threshold, recovery is impossible and the system must treat the data as unavailable."
          },
          {
            "id": "asm-010",
            "text": "Honest Majority of Validators for Data Availability: The data availability sampling scheme assumes that at least 50% of cells are available across the network. This requires a sufficient number of honest validators with correct custody assignments to collectively hold enough cells for recovery."
          },
          {
            "id": "asm-011",
            "text": "Custody Requirement Proportionality: Higher-staked validators (larger effective_balance) are assigned more custody groups (SG-001 get_validators_custody_requirement). The assumption is that validators with more stake have proportionally more resources (bandwidth, storage) and stronger incentive alignment, so burdening them with more custody is both fair and enforceable."
          },
          {
            "id": "asm-012",
            "text": "Sidecar Retention Compliance: Validators MUST retain sidecars for MIN_EPOCHS_FOR_DATA_COLUMN_SIDECARS_REQUESTS epochs (SG-007 INV-001) and MUST serve them on request during this period (INV-002). Non-compliance (premature pruning) degrades data availability but is not directly slashable."
          },
          {
            "id": "asm-013",
            "text": "Gossip Subnet Routing Integrity: Sidecars are published to deterministic subnets via compute_subnet_for_data_column_sidecar (SG-006 INV-002). The assumption is that the subnet mapping function is consistent across all nodes and that the gossip network faithfully routes messages within each subnet."
          },
          {
            "id": "asm-014",
            "text": "Non-Zero Divisor in Polynomial Division: divide_polynomialcoeff (SG-010 INV-001) assumes the divisor polynomial b is not the zero polynomial, and that the leading coefficient b[bpos] is nonzero (INV-003). Division by zero would cause a runtime error or undefined behavior."
          },
          {
            "id": "asm-015",
            "text": "Lagrange Interpolation Point Distinctness: interpolate_polynomialcoeff (SG-011 INV-001) requires all x-values to be distinct for the weight_adjustment inverse (xs[i] - xs[j]).inverse() to exist. Duplicate x-values would cause division by zero in the field, crashing or producing incorrect interpolation."
          },
          {
            "id": "asm-016",
            "text": "Pairing Check Soundness: The bilinear pairing check e(LL, LR) == e(RL, [1]) in verify_cell_kzg_proof_batch_impl (SG-015 INV-001) is assumed to be sound: it rejects with overwhelming probability when the underlying KZG polynomial commitment relationship does not hold."
          }
        ],
        "stride_analysis": [
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Tampering",
            "description": "An adversary submitting a blob with carefully crafted byte sequences that, when deserialized by bytes_to_bls_field, produce field elements that exploit edge cases in polynomial arithmetic (e.g., zero field elements that cause vanishing polynomial issues, or elements near the field modulus BLS_MODULUS that trigger overflow in non-modular implementations).",
            "mitigation": "bytes_to_bls_field must validate that input bytes represent a value strictly less than BLS_MODULUS. The assertion len(blob) == BYTES_PER_BLOB and the fixed segment size of BYTES_PER_FIELD_ELEMENT (SG-001 INV-001) prevent buffer overflows."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Denial of Service",
            "description": "An adversary could submit maximally-sized blobs (BYTES_PER_BLOB) that are computationally expensive to encode into cells, requiring a full inverse FFT (SG-007), CELLS_PER_EXT_BLOB polynomial evaluations (SG-018), and CELLS_PER_EXT_BLOB KZG proof generations (SG-019). The O(n^2) complexity noted in SG-019 INV-003 makes this a realistic resource exhaustion vector.",
            "mitigation": "Rate-limiting blob submissions. The FK20 algorithm is recommended for production (SG-019 INV-003) to reduce proof generation complexity. Cell computation can be parallelized per-coset."
          },
          {
            "trust_boundary_id": "tb-004",
            "threat_type": "Spoofing",
            "description": "If the KZG trusted setup is compromised (toxic waste not destroyed), an adversary possessing the secret trapdoor can forge KZG proofs that validate against arbitrary commitments. This would allow spoofing of data availability: a blob could appear committed and provable while the underlying data is garbage or unavailable.",
            "mitigation": "Multi-party computation ceremonies with hundreds/thousands of participants where only one honest participant is needed. The trusted setup is a one-time operation and its integrity is the foundational security assumption of the entire PCS scheme."
          },
          {
            "trust_boundary_id": "tb-005",
            "threat_type": "Tampering",
            "description": "If KZG_SETUP_G2_MONOMIAL[n] used in the pairing check (SG-015 q_lr) is tampered with or does not correspond to the same trusted setup as KZG_SETUP_G1_MONOMIAL, the verification equation e(LL, LR) == e(RL, [1]) could accept invalid proofs or reject valid ones.",
            "mitigation": "The G1 and G2 setup elements must be loaded from the same verified trusted setup file and validated against known checksums before use. Runtime consistency checks between G1 and G2 elements can detect mismatches."
          },
          {
            "trust_boundary_id": "tb-006",
            "threat_type": "Tampering",
            "description": "If an adversary can manipulate the hash input to compute_verify_cell_kzg_proof_batch_challenge (SG-006) by injecting, reordering, or omitting data before hashing, they could influence the random challenge r to make the batched verification equation hold for invalid proofs. The Fiat-Shamir challenge must bind to ALL verifier-relevant data.",
            "mitigation": "SG-006 INV-001 mandates that all verifier-relevant data is included in the hash input. INV-003 requires the hash input order to be deterministic and canonical. The domain separator (INV-002) prevents cross-protocol manipulation."
          },
          {
            "trust_boundary_id": "tb-006",
            "threat_type": "Spoofing",
            "description": "An adversary could attempt to find two different sets of (commitments, cells, proofs) that produce the same Fiat-Shamir challenge r, allowing them to substitute invalid data that passes batch verification. This is a collision attack on the hash function.",
            "mitigation": "Using a collision-resistant hash function for hash_to_bls_field. The domain separator RANDOM_CHALLENGE_KZG_CELL_BATCH_DOMAIN ensures domain separation."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Tampering",
            "description": "An adversary could submit cells with valid formatting (correct BYTES_PER_CELL length, valid cell_indices) but containing tampered evaluation data that does not correspond to the claimed KZG commitment. The batch verifier must cryptographically reject such inputs.",
            "mitigation": "The pairing-based verification equation (SG-015 INV-001) cryptographically binds cells to commitments via KZG proofs. Random linear combination via the Fiat-Shamir challenge ensures that tampering with any individual cell is detected with overwhelming probability."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Denial of Service",
            "description": "An adversary could submit a large batch of (commitments, cell_indices, cells, proofs) for verification, causing the verifier to perform expensive operations: multiple polynomial interpolations (SG-011 inside SG-015), g1_lincomb operations, and a final pairing check. The number of operations scales linearly with num_cells.",
            "mitigation": "Rate-limiting verification requests. The batch verification itself (single pairing check for all cells, SG-015 INV-005) is already an optimization over individual verification. Maximum batch sizes should be bounded by protocol constants."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Spoofing",
            "description": "An adversary could present a valid proof for one (commitment, cell) pair and attempt to reuse it for a different cell or commitment. The Fiat-Shamir challenge computation includes all commitments, cell indices, cell evaluations, and proofs (SG-006), making such reuse detectable.",
            "mitigation": "The deterministic inclusion of commitment_indices, cell_indices, coset evaluations, and proofs in the Fiat-Shamir hash (SG-006) ensures that any substitution changes the challenge r and invalidates the verification equation."
          },
          {
            "trust_boundary_id": "tb-008",
            "threat_type": "Tampering",
            "description": "An adversary providing partial cells for recovery (SG-024) could supply cells that are individually valid but mutually inconsistent (e.g., cells from different polynomials). The recovery algorithm (SG-023) would produce a polynomial that differs from the original, leading to regenerated cells and proofs that fail verification against the original commitment.",
            "mitigation": "After recovery, the regenerated cells and proofs should be verified against the original KZG commitment using verify_cell_kzg_proof_batch (SG-021). This post-recovery verification step detects inconsistent input cells."
          },
          {
            "trust_boundary_id": "tb-008",
            "threat_type": "Denial of Service",
            "description": "Recovery (SG-023 recover_polynomialcoeff) involves multiple FFTs, inverse FFTs, coset FFTs, and element-wise operations over vectors of size FIELD_ELEMENTS_PER_EXT_BLOB. An adversary could trigger recovery with the minimum number of cells (CELLS_PER_EXT_BLOB / 2) to maximize the size of the vanishing polynomial and thus computational cost.",
            "mitigation": "Recovery is an inherently expensive operation. Nodes should rate-limit recovery attempts and prioritize recovering data for blocks that are on the canonical chain."
          },
          {
            "trust_boundary_id": "tb-008",
            "threat_type": "Information Disclosure",
            "description": "The division step in recovery (SG-023 q_divide: reconstructed = [a / b for a, b in zip(ez_over_coset, zp_over_coset)]) could fail if zp_over_coset contains zero elements. While the coset FFT is specifically designed to avoid this (SG-005 INV-003), a failure would leak information about which cells were missing and potentially reveal side-channel timing information.",
            "mitigation": "The coset FFT evaluation domain (using PRIMITIVE_ROOT_OF_UNITY as shift_factor) is specifically chosen to avoid evaluation points where the vanishing polynomial is zero (SG-005 INV-003). This is an algebraic guarantee, not a runtime check."
          },
          {
            "trust_boundary_id": "tb-009",
            "threat_type": "Tampering",
            "description": "If recover_polynomialcoeff (SG-023) returns an incorrect polynomial (e.g., degree >= FIELD_ELEMENTS_PER_BLOB due to adversarial cells), the subsequent call to compute_cells_and_kzg_proofs_polynomialcoeff (SG-019) would generate cells and proofs for a different polynomial than the original blob. The truncation to FIELD_ELEMENTS_PER_BLOB coefficients (SG-023 INV-003) is the boundary between the extended and original domain.",
            "mitigation": "The recovered polynomial is truncated to degree < FIELD_ELEMENTS_PER_BLOB (SG-023 INV-003). Post-recovery, cells and proofs should be verified against known KZG commitments. High-degree coefficients in the recovered polynomial (beyond FIELD_ELEMENTS_PER_BLOB) should be verified to be zero."
          },
          {
            "trust_boundary_id": "tb-010",
            "threat_type": "Denial of Service",
            "description": "A network-level adversary could selectively drop or delay data column sidecars published to specific gossip subnets, preventing certain columns from reaching peers and degrading data availability below the 50% recovery threshold.",
            "mitigation": "The custody group system distributes columns across multiple subnets and multiple validators. Redundancy in custody assignments ensures that even if some subnet paths are disrupted, sufficient cells remain available for recovery."
          },
          {
            "trust_boundary_id": "tb-010",
            "threat_type": "Repudiation",
            "description": "A validator could claim to have published sidecars to the gossip network but actually withhold them (data withholding attack). Since gossip publication is not cryptographically logged, there is no proof of publication.",
            "mitigation": "Data availability sampling by multiple independent peers detects withheld data. The economic incentive (staked ETH) aligns validators with honest behavior. Peer reputation scoring in GossipSub penalizes nodes that fail to propagate expected data."
          },
          {
            "trust_boundary_id": "tb-011",
            "threat_type": "Tampering",
            "description": "If the beacon state is forked or stale, the effective_balance values used in get_validators_custody_requirement (SG-001) would be incorrect, leading to validators being assigned too few or too many custody groups. Incorrect custody assignments could create coverage gaps where some columns are not held by any validator.",
            "mitigation": "Custody requirements should be computed from the finalized or justified state to prevent fork-based manipulation. VALIDATOR_CUSTODY_REQUIREMENT (minimum 8) provides a floor that ensures every validator stores at least a baseline number of columns."
          },
          {
            "trust_boundary_id": "tb-011",
            "threat_type": "Elevation of Privilege",
